import{_ as t,o as r,c as i,a2 as e}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Riwayat Scan (Repository)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/repository.md","filePath":"guide/repository.md"}'),n={name:"guide/repository.md"};function o(d,a,s,l,g,h){return r(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="riwayat-scan-repository" tabindex="-1">Riwayat Scan (Repository) <a class="header-anchor" href="#riwayat-scan-repository" aria-label="Permalink to &quot;Riwayat Scan (Repository)&quot;">​</a></h1><p>Halaman ini menyimpan seluruh riwayat pemeriksaan X-Ray yang pernah dilakukan.</p><h2 id="filter-pencarian" tabindex="-1">Filter &amp; Pencarian <a class="header-anchor" href="#filter-pencarian" aria-label="Permalink to &quot;Filter &amp; Pencarian&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Filter</th><th>Deskripsi</th></tr></thead><tbody><tr><td><strong>MAWB</strong></td><td>Cari berdasarkan Master Air Waybill</td></tr><tr><td><strong>HAWB</strong></td><td>Cari berdasarkan House Air Waybill</td></tr><tr><td><strong>Screener</strong></td><td>Cari berdasarkan nama operator</td></tr><tr><td><strong>Tanggal Awal</strong></td><td>Filter dari tanggal tertentu</td></tr><tr><td><strong>Tanggal Akhir</strong></td><td>Filter hingga tanggal tertentu</td></tr><tr><td><strong>Status</strong></td><td>Semua / Finished XRay / Pending XRay</td></tr></tbody></table><h2 id="statistik-cards" tabindex="-1">Statistik Cards <a class="header-anchor" href="#statistik-cards" aria-label="Permalink to &quot;Statistik Cards&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kartu</th><th>Deskripsi</th></tr></thead><tbody><tr><td><strong>Total Scans</strong></td><td>Total seluruh scan yang pernah dilakukan</td></tr><tr><td><strong>Finished XRay</strong></td><td>Jumlah kargo yang dinyatakan lolos</td></tr><tr><td><strong>Pending XRay</strong></td><td>Jumlah kargo yang ditunda</td></tr><tr><td><strong>Submitted Customs</strong></td><td>Jumlah yang sudah dikirim ke bea cukai</td></tr></tbody></table><h2 id="aksi-pada-data-scan" tabindex="-1">Aksi pada Data Scan <a class="header-anchor" href="#aksi-pada-data-scan" aria-label="Permalink to &quot;Aksi pada Data Scan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tombol</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>👁 Lihat Snapshot</strong></td><td>Lihat seluruh gambar (Top View, Side View, Foto Barang, hasil crop AI) dalam modal dengan zoom</td></tr><tr><td><strong>✏ Edit</strong></td><td>Edit data scan (memerlukan konfirmasi password)</td></tr><tr><td><strong>🔄 Re-Scan</strong></td><td>Kembali ke halaman Screening dengan data MAWB/HAWB terisi</td></tr><tr><td><strong>📤 Submit Customs</strong></td><td>Kirim data ke bea cukai (CEISA) — mencatat timestamp submission</td></tr><tr><td><strong>🗑 Hapus</strong></td><td>Hapus riwayat scan (memerlukan konfirmasi password)</td></tr></tbody></table><h2 id="detail-snapshot" tabindex="-1">Detail Snapshot <a class="header-anchor" href="#detail-snapshot" aria-label="Permalink to &quot;Detail Snapshot&quot;">​</a></h2><ol><li>Klik ikon <strong>Mata (Eye)</strong> pada baris data untuk melihat snapshot lengkap</li><li>Modal akan menampilkan: <ul><li><strong>Top View X-Ray</strong> — gambar dari atas</li><li><strong>Side View X-Ray</strong> — gambar dari samping</li><li><strong>Foto Barang</strong> — foto fisik (jika diunggah)</li><li><strong>Hasil Crop AI</strong> — semua crop koli terdeteksi</li></ul></li><li>Klik pada gambar untuk memperbesar tampilan (Zoom in/out)</li></ol><blockquote><p>Gambar ditampilkan langsung dari folder <code>uploads/</code> pada server dalam format <strong>PNG lossless</strong>.</p></blockquote><h2 id="export-excel" tabindex="-1">Export Excel <a class="header-anchor" href="#export-excel" aria-label="Permalink to &quot;Export Excel&quot;">​</a></h2><p>Ekspor data ke Excel dengan embedded gambar crop di dalam sel. File Excel memiliki:</p><ul><li>Header dengan styling profesional</li><li>Warna baris selang-seling</li><li>Gambar crop koli tertanam dalam sel</li></ul><h2 id="verifikasi-cargo" tabindex="-1">Verifikasi Cargo <a class="header-anchor" href="#verifikasi-cargo" aria-label="Permalink to &quot;Verifikasi Cargo&quot;">​</a></h2><p>Tabel menampilkan badge verifikasi:</p><ul><li>✅ <strong>Hijau</strong> — Kargo cocok dengan data manifest</li><li>❌ <strong>Merah</strong> — Kargo tidak ditemukan di data manifest</li></ul>',17)])])}const u=t(n,[["render",o]]);export{p as __pageData,u as default};
